129→private fun ASTNode.getElementsPerLine(): List<ParsedLine> {
130→    val parsedLines = mutableListOf<ParsedLine>()
131→    val lines = text.split("\n")
132→    var offset = 0
133→    for (line in lines) {
134→        val elements = mutableListOf<ASTNode>()
135→        var el = psi.findElementAt(offset)?.node
136→        while (el != null && el.startOffset < offset + line.length) {
137→            elements.add(el)
138→            el = el.nextLeaf()
139→        }
140→        parsedLines.add(ParsedLine(line, offset, elements))
141→        offset += line.length + 1 // +1 for the newline which is stripped due to the splitting of the lines
142→    }
143→    return parsedLines
144→}
145→
146→private data class ParsedLine(
147→    val line: String,
148→    val offset: Int,
149→    val elements: List<ASTNode>,
150→) {
151→    fun lineLength(ignoreBackTickedIdentifier: Boolean): Int {
152→        return if (ignoreBackTickedIdentifier) {
153→            line.length - totalLengthBacktickedElements()
154→        } else {
155→            line.length
156→        }
157→    }
158→
159→    private fun totalLengthBacktickedElements(): Int {
160→        return elements
161→            .filterIsInstance(PsiElement::class.java)
162→            .filter { it.text.matches(BACKTICKED_IDENTIFIER_REGEX) }
163→            .sumOf(PsiElement::getTextLength)
164→    }
165→
166→    private companion object {
167→        val BACKTICKED_IDENTIFIER_REGEX = Regex("`.*`")
168→    }
169→}
