public class FunctionReturnTypeSpacingRule :
    StandardRule(
        id = "function-return-type-spacing",
        usesEditorConfigProperties = setOf(MAX_LINE_LENGTH_PROPERTY),
    ),
    Rule.Experimental {
    private var maxLineLength = MAX_LINE_LENGTH_PROPERTY.defaultValue

    override fun beforeFirstNode(editorConfig: EditorConfig) {
        maxLineLength = editorConfig[MAX_LINE_LENGTH_PROPERTY]
    }

    override fun beforeVisitChildNodes(
        node: ASTNode,
        autoCorrect: Boolean,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
    ) {
        node.firstChildNode
        node
            .takeIf { node.elementType == FUN }
            ?.let { node.findChildByType(COLON) }
            ?.let { colonNode ->
                removeWhiteSpaceBetweenClosingParenthesisAndColon(colonNode, emit, autoCorrect)
                fixWhiteSpaceBetweenColonAndReturnType(colonNode, emit, autoCorrect, node)
            }
    }

    private fun removeWhiteSpaceBetweenClosingParenthesisAndColon(
        node: ASTNode,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
        autoCorrect: Boolean,
    ) {
        require(node.elementType == COLON)
        node
            .prevLeaf()
            ?.takeIf { it.elementType == WHITE_SPACE }
            ?.let { whitespaceBeforeColonNode ->
                emit(whitespaceBeforeColonNode.startOffset, "Unexpected whitespace", true)
                if (autoCorrect) {
                    whitespaceBeforeColonNode.treeParent?.removeChild(whitespaceBeforeColonNode)
                }
            }
    }

    private fun fixWhiteSpaceBetweenColonAndReturnType(
        node: ASTNode,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
        autoCorrect: Boolean,
        functionNode: ASTNode,
    ) {
        require(node.elementType == COLON)
        node
            .nextLeaf()
            ?.takeIf { it.elementType == WHITE_SPACE }
            .let { whiteSpaceAfterColon ->
                if (whiteSpaceAfterColon?.text != " ") {
                    // Check if this is a parameterless function and if the fix would exceed max line length
                    if (isParameterlessFunction(functionNode) && wouldExceedMaxLineLength(node, whiteSpaceAfterColon)) {
                        // Don't fix spacing in this case to avoid violating max-line-length
                        return@let
                    }
                    emit(node.startOffset, "Single space expected between colon and return type", true)
                    if (autoCorrect) {
                        node.upsertWhitespaceAfterMe(" ")
                    }
                }
            }
    }

    private fun isParameterlessFunction(node: ASTNode): Boolean {
        val valueParameterList = node.findChildByType(VALUE_PARAMETER_LIST) ?: return true
        return valueParameterList
            .children()
            .none { it.elementType == VALUE_PARAMETER }
    }

    private fun wouldExceedMaxLineLength(
        colonNode: ASTNode,
        whiteSpaceAfterColon: ASTNode?,
    ): Boolean {
        if (maxLineLength == MAX_LINE_LENGTH_PROPERTY_OFF) {
            return false
        }

        // Calculate the current line length before the fix
        val currentLineLength = calculateCurrentLineLength(colonNode, whiteSpaceAfterColon)

        // The fix will add 1 space (removing current whitespace and adding a single space)
        // So the new line length would be currentLineLength + 1
        val newLineLength = currentLineLength + 1

        return newLineLength > maxLineLength
    }

    private fun calculateCurrentLineLength(
        colonNode: ASTNode,
        whiteSpaceAfterColon: ASTNode?,
    ): Int {
        // Find the start of the line containing the colon
        var currentNode: ASTNode? = colonNode
        var lineOffset = colonNode.startOffset

        while (currentNode != null) {
            val prev = currentNode.prevLeaf(includeEmpty = false)
            if (prev == null) {
                break
            }
            if (prev.elementType == WHITE_SPACE && prev.textContains('\n')) {
                lineOffset = prev.startOffset + 1 // Start after the newline
                break
            }
            lineOffset = minOf(lineOffset, prev.startOffset)
            currentNode = prev
        }

        // Find the end of the line containing the colon
        currentNode = colonNode
        var lineEndOffset = colonNode.startOffset + colonNode.textLength

        while (currentNode != null) {
            val next = currentNode.nextLeaf(includeEmpty = false)
            if (next == null) {
                break
            }
            if (next.elementType == WHITE_SPACE && next.textContains('\n')) {
                break
            }
            lineEndOffset = maxOf(lineEndOffset, next.startOffset + next.textLength)
            currentNode = next
        }

        // Find the parent node to get the full text
        val rootNode = colonNode.treeParent?.treeParent ?: return 0
        val nodeText = rootNode.text

        // Calculate line length from the text
        val lineStartIndex = lineOffset - rootNode.startOffset
        val lineEndIndex = lineEndOffset - rootNode.startOffset

        if (lineStartIndex < 0 || lineEndIndex > nodeText.length) {
            return 0
        }

        val lineText = nodeText.substring(lineStartIndex, lineEndIndex)
        // Get the last line (in case there are multiple newlines)
        val lastLineIndex = lineText.lastIndexOf('\n')
        val relevantLineText = if (lastLineIndex >= 0) {
            lineText.substring(lastLineIndex + 1)
        } else {
            lineText
        }

        return relevantLineText.length
    }
}

