            }
    }

    private fun removeWhiteSpaceBetweenClosingParenthesisAndColon(
        node: ASTNode,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
        autoCorrect: Boolean,
    ) {
        require(node.elementType == COLON)
        node
            .prevLeaf()
            ?.takeIf { it.elementType == WHITE_SPACE }
            ?.let { whitespaceBeforeColonNode ->
                emit(whitespaceBeforeColonNode.startOffset, "Unexpected whitespace", true)
                if (autoCorrect) {
                    whitespaceBeforeColonNode.treeParent?.removeChild(whitespaceBeforeColonNode)
                }
            }
    }

    private fun fixWhiteSpaceBetweenColonAndReturnType(
        node: ASTNode,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
        autoCorrect: Boolean,
        functionNode: ASTNode,
    ) {
        require(node.elementType == COLON)
        node
            .nextLeaf()
            ?.takeIf { it.elementType == WHITE_SPACE }
            .let { whiteSpaceAfterColon ->
                if (whiteSpaceAfterColon?.text != " ") {
                    // Check if this is a parameterless function and if the fix would exceed max line length
                    if (isParameterlessFunction(functionNode) && wouldExceedMaxLineLength(node, whiteSpaceAfterColon)) {
                        // Don't fix spacing in this case to avoid violating max-line-length
                        return@let
                    }
                    emit(node.startOffset, "Single space expected between colon and return type", true)
                    if (autoCorrect) {
                        node.upsertWhitespaceAfterMe(" ")
                    }
                }
            }
    }

    private fun isParameterlessFunction(node: ASTNode): Boolean {
        val valueParameterList = node.findChildByType(VALUE_PARAMETER_LIST) ?: return true
        return valueParameterList
            .children()
            .none { it.elementType == VALUE_PARAMETER }
    }

    private fun wouldExceedMaxLineLength(
        colonNode: ASTNode,
        whiteSpaceAfterColon: ASTNode?,
    ): Boolean {
        if (maxLineLength == MAX_LINE_LENGTH_PROPERTY_OFF) {
            return false
        }

        // Calculate current line length
        val currentLineLength = calculateLineLength(colonNode)

        // If already a single-line format, it won't increase in length
        val isCurrentSingleLine = !whiteSpaceAfterColon?.textContains('\n') ?: false

        // Calculate potential new length
        val resultLength = if (isCurrentSingleLine) {
            // Current whitespace is not a newline, replacing with single space won't change length significantly
            currentLineLength
        } else {
            // Current has newline, removing it and adding single space will join lines
            val indent = colonNode.lineIndent()
            val returnTypeNode = whiteSpaceAfterColon?.nextLeaf { it.elementType != WHITE_SPACE }
            return returnTypeNode?.text?.let { returnTypeText ->
                val signatureBeforeColon = getSignatureBeforeColon(colonNode)
                signatureBeforeColon.length + 1 + 1 + returnTypeText.length // colon + space + return type
            } ?: false
        }

        return resultLength > maxLineLength
    }

    private fun calculateLineLength(colonNode: ASTNode): Int {
        // Find the line containing the colon and return its length
        val rootNode = colonNode.treeParent?.treeParent ?: return 0
        val nodeText = rootNode.text

        // Find the start of the line
        var currentIndex = colonNode.startOffset - rootNode.startOffset
        while (currentIndex > 0 && nodeText[currentIndex - 1] != '\n') {
            currentIndex--
        }

        // Find the end of the line
        var endIndex = currentIndex
        while (endIndex < nodeText.length && nodeText[endIndex] != '\n') {
            endIndex++
        }

        val lineText = nodeText.substring(currentIndex, endIndex)
        return lineText.length
    }

    private fun getSignatureBeforeColon(colonNode: ASTNode): String {
        // Find the function keyword and calculate length up to colon
        val funNode = colonNode.treeParent?.findChildByType(FUN_KEYWORD) ?: return ""
        val rootNode = funNode.treeParent?.treeParent ?: return ""
        val nodeText = rootNode.text

        val startIndex = funNode.startOffset - rootNode.startOffset
        val endIndex = colonNode.startOffset - rootNode.startOffset

        return if (startIndex >= 0 && endIndex < nodeText.length) {
            nodeText.substring(startIndex, endIndex)
        } else {
            ""
        }
    }
}

