        return valueParameterList
            .children()
            .none { it.elementType == VALUE_PARAMETER }
    }

    private fun wouldExceedMaxLineLength(
        colonNode: ASTNode,
        whiteSpaceAfterColon: ASTNode?,
        functionNode: ASTNode,
    ): Boolean {
        if (maxLineLength == MAX_LINE_LENGTH_PROPERTY_OFF) {
            return false
        }

        // Check if there's a newline between the closing parenthesis and colon
        val hasNewlineBeforeColon = colonNode.prevLeaf()
            ?.let { it.elementType == WHITE_SPACE && it.textContains('\n') }
            ?: false

