        }
    }

    private fun getFunctionSignatureText(functionNode: ASTNode, colonNode: ASTNode): String {
        val rootNode = colonNode.treeParent?.treeParent ?: return ""
        val nodeText = rootNode.text

        val colonIndex = colonNode.startOffset - rootNode.startOffset
        if (colonIndex < 0 || colonIndex >= nodeText.length) {
            return ""
        }

        // Find start of signature (beginning of line containing colon)
        var startIndex = colonIndex
        while (startIndex > 0 && nodeText[startIndex - 1] != '\n') {
            startIndex--
        }

        return nodeText.substring(startIndex, colonIndex)
    }

    private fun getSignatureLengthBeforeColon(colonNode: ASTNode): Int {
        val rootNode = colonNode.treeParent?.treeParent ?: return 0
        val nodeText = rootNode.text

        val colonIndex = colonNode.startOffset - rootNode.startOffset
        if (colonIndex < 0 || colonIndex >= nodeText.length) {
            return 0
        }

        // Find the start of the line from colon
        var startIndex = colonIndex
        while (startIndex > 0 && nodeText[startIndex - 1] != '\n') {
            startIndex--
        }

        return colonIndex - startIndex
